using UnityEditor;
using UnityEngine;

public class ControllerChecker
{
    public static string Check()
    {
        // PlayerModel Animator InstanceID: 54502
        Animator anim = (Animator)EditorUtility.InstanceIDToObject(54502);
        if (anim == null) return "Animator not found";
        if (anim.runtimeAnimatorController == null) return "RuntimeAnimatorController is null";
        return $"Animator Controller: {anim.runtimeAnimatorController.name} (InstanceID: {anim.runtimeAnimatorController.GetInstanceID()})";
    }
}
